import {getI18n,sptI18n,useSptTranslation} from "@spotter/i18n-sdk";

declare global {
    interface Window {
        __SPOTTER_APP_BOOT_DATA__?: ApplicationBootData & Record<string, any>;
        // 国际化实例,这里会在主应用i18n init完成后挂载到window
        __SPOTTER_I18N_DATA__:MainI18n;
    }
}
export interface MainI18n {
    i18n: ReturnType<typeof getI18n>,
    sptI18n:typeof sptI18n,
    useSptTranslation:typeof useSptTranslation,
}
export interface ApplicationBootData {
    app: {
        name: string;
        code: string;
        apiUrl: string;
        apiTag?: string;
        larkUrl: string;
        biUrl: string;
        messageBucketName: string;
        imageBucketName: string;
        imageCustomFolderName: string;
        videoBucketName: string;
        videoCustomFolderName: string;
        businessImageBucketName: string;
        businessImageCustomFolderName: string;
        contractBucketName: string;
        performanceBucketName: string;
        env?: string;
        sessionkey?: string;
        ssoApiUrl?: string;
        ssoAppCode?: string;
        ssoToken?: string;
        browsersCache?: string
    },
}

export type BootDataSection = keyof ApplicationBootData;

export function getAppBootData(): ApplicationBootData;
export function getAppBootData<T extends BootDataSection>(scope?: T): ApplicationBootData[T];

/**
 * 获取应用的初始化数据
 * @param scope
 * @TODO 暂时不支持动态扩展初始化数据的字段
 */
export function getAppBootData(scope?: BootDataSection): any {
    if (scope) {
        return window.__SPOTTER_APP_BOOT_DATA__?.[scope];
    }
    return window.__SPOTTER_APP_BOOT_DATA__;
}
/**
 * 获取应用挂载的国际化实例
 */
export function getMainI18n(){
    return window.__SPOTTER_I18N_DATA__;
}

